qss:
QWidget { background: #f5f6f8; color: #15171a; font-family: Segoe UI, Arial, sans-serif; font-size: 10pt; }
QMainWindow, QDialog { background: #f5f6f8; }
QGroupBox { background: #ffffff; border: 1px solid #c6cbd3; border-radius: 8px; margin-top: 12px; padding: 10px; font-weight: bold; }
QGroupBox::title { subcontrol-origin: margin; left: 12px; padding: 0 4px; color: #2563eb; }
QTabWidget::pane { border: 1px solid #c6cbd3; background: #ffffff; }
QTabBar::tab { background: #ffffff; color: #15171a; padding: 8px 14px; border: 1px solid #c6cbd3; border-bottom: none; min-width: 100px; }
QTabBar::tab:selected { background: #2563eb; color: #ffffff; font-weight: bold; }
QTabBar::tab:hover { background: #e8efff; color: #ffffff; }
QPushButton { background: #e8efff; color: #ffffff; border: 1px solid #2563eb; border-radius: 6px; padding: 7px 12px; font-weight: 600; }
QPushButton:hover { background: #2563eb; color: #ffffff; }
QPushButton:disabled { background: #a7aab0; color: #ffffff; border-color: #c6cbd3; }
QLineEdit, QTextEdit, QTextBrowser, QPlainTextEdit, QComboBox, QSpinBox, QDoubleSpinBox { background: #ffffff; color: #15171a; border: 1px solid #c6cbd3; border-radius: 5px; padding: 5px; selection-background-color: #2563eb; selection-color: #ffffff; }
QComboBox QAbstractItemView { background: #ffffff; color: #15171a; selection-background-color: #2563eb; selection-color: #ffffff; border: 1px solid #c6cbd3; }
QTableWidget { background: #ffffff; alternate-background-color: #ffffff; color: #15171a; gridline-color: #c6cbd3; selection-background-color: #2563eb; selection-color: #ffffff; }
QHeaderView::section { background: #2563eb; color: #ffffff; padding: 6px; border: 1px solid #c6cbd3; font-weight: bold; }
QScrollBar:vertical { background: #ffffff; width: 14px; }
QScrollBar::handle:vertical { background: #2563eb; border-radius: 6px; min-height: 24px; }
QScrollBar:horizontal { background: #ffffff; height: 14px; }
QScrollBar::handle:horizontal { background: #2563eb; border-radius: 6px; min-width: 24px; }
QCheckBox { spacing: 6px; }
QLabel { color: #15171a; }
